import{_ as t,c as p,ap as a,o as _}from"./chunks/framework.CCxIPCIe.js";const m=JSON.parse('{"title":"三九七","description":"","frontmatter":{"title":"三九七","date":"2026-01-21T09:39:44.229Z","length":"1126字","time":"4分钟","aside":false,"hash":-855253069},"headers":[],"relativePath":"idea/397.md","filePath":"idea/397.md"}'),s={name:"idea/397.md"};function i(r,e,o,n,d,c){return _(),p("div",null,e[0]||(e[0]=[a("<p>资本为了维持自己的增殖，最害怕无法进入再生产循环，那样一来几万亿的财富就失去了稳定的利润。但资本更害怕风险，一旦进入了循环就有亏本的危险，于是在无数交易中，行业形成了平均利润率，它把单个部门之间此消彼长的利润平均化为一张可供金融家查阅的报表。</p><p>利润率是金融资本的遇到的第一个幻象，它许诺了一个优美的公式：资本*利率=利润。一个简单的乘号，无限平滑了生产环节中的矛盾和冲突，把生产部门变成一个只有输入输出的黑箱，暗示着一端可以输入无限的财富——无限的财富，不变的利润率，永恒的线性增长。</p><p>于是，金融资本家或是它们的职业经理人们每天面对的不过是成百上千个标定了数字的黑箱——不把钱放进黑箱中是对时间的浪费，资本主义的时间一经流失，便失去了积累的可能。（如同现代人在休息时面对未经利用的时间的内疚感）</p><p>为了保持不变的利润率，黑箱内部却在时刻经历生死斗争，压榨、裁员，没有什么比用工人的血肉来填补实践的裂缝更容易的办法了。但幻象永远会失败，一旦连工人的血肉都无法阻止资本的流血时，利润率就会下滑，资本就蠢蠢欲动随时准备脱身。</p><p>因而，焦虑的资本始终在找寻那个无限的黑箱，那个可以无限的容纳它的聚宝盆。AI，或者说 AI 的规模律作为第二个幻象，承接了它的期望——无限的财富、无限的算力、无限的智能。但并非线性的增长，而是对数线性。</p><p>对数线性的好处在于，它更能驯服资本的焦虑，维持住匮乏的欲望，资本不会怀疑是这个黑箱失灵了，反而科学规律诚恳的告诉它边际效益就是会递减，但这效益是稳定的。资本只恨自己投入的不够多，这黑箱吃的还不够快。</p><p>于是，黑箱里的工人被前所未有的天量资本俘虏着，我们伟大的资本似乎要冲破它的最后屏障，那个阻碍它增长的最后的血肉屏障，一旦实现了 agi，可变资本就变成可有可无的东西，资本就不再需要雇佣唯一的不稳定因素。在这个祥和的乌托邦中，一切都是资本的直接兑换物，机器、算力、智能被源源不断的生产出来。从这个意义上说，ai 算法工程师将是最后的工人。</p><p>可问题是这个黑箱迟迟没有输出，有的只是被言语不断堆砌的预期和估值。资本被语言欺骗了，这个对手比它更为古老。资本认为自己天然的占有利润，正如它误以为语言天然的占有智能，于是资本向往一个完全独立于主体（工人）的增殖路径，正如它向往语言能够完全独立于主体（人）运行而产生智能。殊不知是主体的劳动让资本增殖，而智能是主体的运动，语言只是那种运动的同步辐射（表象）。</p><p>除了资本面对语言意淫般的自欺，同样的语言则以另一种方式欺骗资本。员工为了不在绩效考核中被淘汰编造进步，而这进步又通过小老板、中老板、大老板这一串串发条最终传递到黑箱上的数字，于是焦虑的资本又得以多持有一秒。所以所谓的等级制，所谓的向上管理，本质上是向金融资本管理、向报表管理。周报、简历、论文，无一例外都是报表。</p><p>一旦想通这一点就无所谓羞耻，欺骗一个有着原罪父母的二代，无论它再如何温情，都是欣然的报复，何况这种报复是对它的欺压的反作用。如果能戴上这伪善的面具作斗争，那么我将其视为一种享乐。</p>",10)]))}const f=t(s,[["render",i]]);export{m as __pageData,f as default};
